class EvoOLED(framebuf.FrameBuffer):
    def __init__(self, i2c, channel, addr=0x3C):
        self.width = 128
        self.height = 64
        self.pages = self.height // 8

        self.i2c = i2c
        self.channel = channel
        self.addr = addr

        self.buffer = bytearray(self.width * self.pages)
        super().__init__(self.buffer, self.width, self.height, framebuf.MONO_VLSB)

        self._fontSize = 8
        self._flipped = False

        self._cmd = bytearray(2)
        self._pagebuf = bytearray(self.width + 1)
        self._pagebuf[0] = 0x40

    def write_cmd(self, cmd):
        self._cmd[0] = 0x80
        self._cmd[1] = cmd
        self.i2c.writeto(self.channel, self.addr, self._cmd)

    def write_page(self, buf):
        self._pagebuf[1:] = buf
        self.i2c.writeto(self.channel, self.addr, self._pagebuf)

    def _get_column_offset(self):
        return 4 if self._flipped else 0

    def _apply_orientation(self):
        if self._flipped:
            self.write_cmd(_SET_SEG_REMAP | 0x00)
            self.write_cmd(_SET_COM_OUT_DIR | 0x00)
        else:
            self.write_cmd(_SET_SEG_REMAP | 0x01)
            self.write_cmd(_SET_COM_OUT_DIR | 0x08)

    def begin(self):
        self.write_cmd(_SET_DISP | 0x00)
        self.write_cmd(_SET_DISP_START_LINE | 0x00)

        self.write_cmd(_SET_SEG_REMAP | 0x01)
        self.write_cmd(_SET_MUX_RATIO)
        self.write_cmd(0x3F)
        self.write_cmd(_SET_COM_OUT_DIR | 0x08)
        self.write_cmd(_SET_DISP_OFFSET)
        self.write_cmd(0x00)
        self.write_cmd(_SET_COM_PIN_CFG)
        self.write_cmd(0x12)
        self.write_cmd(_SET_DISP_CLK_DIV)
        self.write_cmd(0x80)
        self.write_cmd(_SET_PRECHARGE)
        self.write_cmd(0xF1)
        self.write_cmd(_SET_VCOM_DESEL)
        self.write_cmd(0x30)
        self.write_cmd(_SET_CONTRAST)
        self.write_cmd(0xCF)
        self.write_cmd(_SET_ENTIRE_ON)
        self.write_cmd(_SET_NORM_INV)
        self.write_cmd(_SET_CHARGE_PUMP)
        self.write_cmd(0x14)

        self.write_cmd(_SET_MEM_ADDR)
        self.write_cmd(0x02)

        self.write_cmd(_SET_DISP | 0x01)

        self._flipped = False
        self._apply_orientation()

        self.fill(0)
        self.setFontSize(8)
        self.show()
        return True

    def show(self):
        self._apply_orientation()
        col = self._get_column_offset()

        for page in range(self.pages):
            self.write_cmd(_SET_PAGE_ADDRESS | page)
            self.write_cmd(_LOW_COLUMN_ADDRESS | (col & 0x0F))
            self.write_cmd(_HIGH_COLUMN_ADDRESS | ((col >> 4) & 0x0F))

            start = page * self.width
            end = start + self.width
            self.write_page(self.buffer[start:end])

    def clearDisplay(self):
        self.fill(0)
        self.show()

    def drawDisplay(self):
        self.show()

    def poweron(self):
        self.write_cmd(_SET_DISP | 0x01)

    def poweroff(self):
        self.write_cmd(_SET_DISP | 0x00)

    def sleep(self, value):
        self.write_cmd(_SET_DISP | (0x00 if value else 0x01))

    def setContrast(self, value):
        value = max(0, min(255, int(value)))
        self.write_cmd(_SET_CONTRAST)
        self.write_cmd(value)

    def invertDisplay(self, invert=True):
        self.write_cmd(_SET_NORM_INV | (1 if invert else 0))

    def setFlipOrientation(self, flip=False, draw=True):
        self._flipped = bool(flip)
        self._apply_orientation()
        if draw:
            self.show()

    # None = toggle
    # True = force flipped
    # False = force normal
    def flipDisplayOrientation(self, flip=None):
        if flip is None:
            self._flipped = not self._flipped
        else:
            self._flipped = bool(flip)
        self.show()

    def setFontSize(self, size):
        if size not in FONT_DATA:
            size = 7
        self._fontSize = size
        self._fontAscent, self._fontHeight, self._glyphs = FONT_DATA[size]

    def _get_glyph(self, ch):
        code = ord(ch)
        glyph = None
        if 32 <= code <= 255:
            glyph = self._glyphs[code - 32]
        if glyph is None and 32 <= ord('?') <= 255:
            glyph = self._glyphs[ord('?') - 32]
        return glyph

    def _draw_glyph(self, ch, x, y):
        glyph = self._get_glyph(ch)
        if glyph is None:
            return 0

        dx, x_off, y_off, w, h, bmp = glyph
        if w <= 0 or h <= 0:
            return dx

        x0 = int(x) + x_off
        y0 = int(y) + self._fontAscent - h - y_off
        pages = (h + 7) // 8

        for col in range(w):
            if x0 + col < 0 or x0 + col >= self.width:
                continue
            for page in range(pages):
                b = bmp[col + page * w]
                yy = y0 + page * 8
                for bit in range(8):
                    py = yy + bit
                    if py < 0 or py >= self.height:
                        continue
                    if page * 8 + bit >= h:
                        break
                    if b & (1 << bit):
                        self.pixel(x0 + col, py, 1)

        return dx

    def _draw_text(self, text, x, y):
        cx = int(x)
        for ch in str(text):
            cx += self._draw_glyph(ch, cx, int(y))

    def writeToDisplay(self, value, x, y, clear=False, draw=False):
        if clear:
            self.fill(0)
        self._draw_text(value, x, y)
        if draw:
            self.show()

    def writeLineToDisplay(self, value, line, clear=False, draw=False):
        self.writeToDisplay(value, 0, int(line) * int(self._fontSize), clear, draw)

    def drawPixel(self, x, y, clear=False, draw=False):
        self.pixel(int(x), int(y), 0 if clear else 1)
        if draw:
            self.show()

    def drawLine(self, x0, y0, x1, y1, clear=False, draw=False):
        color = 0 if clear else 1
        self.line(int(x0), int(y0), int(x1), int(y1), color)
        if draw:
            self.show()

    def drawRect(self, x, y, w, h, fill=False, clear=False, draw=False):
        color = 0 if clear else 1
        if fill:
            self.fill_rect(int(x), int(y), int(w), int(h), color)
        else:
            self.rect(int(x), int(y), int(w), int(h), color)
        if draw:
            self.show()

    def drawCircle(self, x, y, r, fill=False, clear=False, draw=False):
        color = 0 if clear else 1
        x = int(x)
        y = int(y)
        r = int(r)

        if fill:
            for yy in range(-r, r + 1):
                xx = int((r * r - yy * yy) ** 0.5)
                self.hline(x - xx, y + yy, 2 * xx + 1, color)
        else:
            f = 1 - r
            ddF_x = 1
            ddF_y = -2 * r
            xx = 0
            yy = r

            self.pixel(x, y + r, color)
            self.pixel(x, y - r, color)
            self.pixel(x + r, y, color)
            self.pixel(x - r, y, color)

            while xx < yy:
                if f >= 0:
                    yy -= 1
                    ddF_y += 2
                    f += ddF_y
                xx += 1
                ddF_x += 2
                f += ddF_x

                self.pixel(x + xx, y + yy, color)
                self.pixel(x - xx, y + yy, color)
                self.pixel(x + xx, y - yy, color)
                self.pixel(x - xx, y - yy, color)
                self.pixel(x + yy, y + xx, color)
                self.pixel(x - yy, y + xx, color)
                self.pixel(x + yy, y - xx, color)
                self.pixel(x - yy, y - xx, color)

        if draw:
            self.show()

    def drawTriangle(self, x0, y0, x1, y1, x2, y2, clear=False, draw=False):
        color = 0 if clear else 1
        self.line(int(x0), int(y0), int(x1), int(y1), color)
        self.line(int(x1), int(y1), int(x2), int(y2), color)
        self.line(int(x2), int(y2), int(x0), int(y0), color)
        if draw:
            self.show()